mapper.update:
UPDATE t_oa_bank
SET deleted_flag = #{deletedFlag}
WHERE bank_id = #{bankId}

mapper.select:
SELECT *
FROM t_oa_bank
WHERE enterprise_id = #{enterpriseId}
AND account_number = #{accountNumber}
AND deleted_flag = #{deletedFlag}

    AND bank_id != #{excludeBankId}

SELECT ob.*,
oe.enterprise_name
FROM t_oa_bank ob
LEFT JOIN t_oa_enterprise oe ON ob.enterprise_id = oe.enterprise_id

    ob.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(ob.bank_name,#{queryForm.keywords}) OR INSTR(ob.account_name,#{queryForm.keywords}) OR
        INSTR(ob.account_number,#{queryForm.keywords}) OR INSTR(ob.create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(ob.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(ob.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND ob.disabled_flag = #{queryForm.disabledFlag}


        AND ob.enterprise_id = #{queryForm.enterpriseId}



    ORDER BY ob.create_time DESC

SELECT ob.*,
       oe.enterprise_name
FROM t_oa_bank ob
LEFT JOIN t_oa_enterprise oe ON ob.enterprise_id = oe.enterprise_id
WHERE ob.bank_id = #{bankId}
  AND ob.deleted_flag = #{deletedFlag}
